class WalletStore(private val secureStore: SecureStore) {

    private val balanceKey = "wallet_balance"
    private val currencyKey = "wallet_currency"
    private val txPrefix = "wallet_tx_"
    private val txIndexKey = "wallet_tx_index"

    fun getBalance(): Money {
        val bal = secureStore.getString(balanceKey)?.toLongOrNull() ?: 0L
        val cur = secureStore.getString(currencyKey) ?: "USD"
        return Money(bal, cur)
    }

    fun setCurrencyIfEmpty(currency: String) {
        val cur = secureStore.getString(currencyKey)
        if (cur.isNullOrBlank()) secureStore.putString(currencyKey, currency)
    }

    fun setBalance(balanceMinor: Long, currency: String) {
        secureStore.putString(balanceKey, balanceMinor.toString())
        secureStore.putString(currencyKey, currency)
    }

    fun applyTransaction(type: WalletTransaction.Type, amountMinor: Long, currency: String, reference: String? = null, metadata: Map<String, String> = emptyMap()): WalletTransaction {
        require(amountMinor > 0)
        val current = getBalance()
        val newBalance = when (type) {
            WalletTransaction.Type.CREDIT -> current.amountMinor + amountMinor
            WalletTransaction.Type.DEBIT -> {
                val nb = current.amountMinor - amountMinor
                require(nb >= 0) { "Insufficient balance" }
                nb
            }
        }
        val tx = WalletTransaction(
            id = UUID.randomUUID().toString(),
            type = type,
            amountMinor = amountMinor,
            currency = currency,
            createdAtEpochMs = System.currentTimeMillis(),
            reference = reference,
            metadata = metadata
        )
        recordTransaction(tx)
        setBalance(newBalance, currency)
        return tx
    }

    fun listRecentTransactions(limit: Int = 50): List<WalletTransaction> {
        val idx = secureStore.getString(txIndexKey)?.toIntOrNull() ?: 0
        val result = ArrayList<WalletTransaction>(limit.coerceAtMost(idx))
        var i = idx
        while (i > 0 && result.size < limit) {
            val raw = secureStore.getString("$txPrefix$i") ?: run { i--; continue }
            parseTx(raw)?.let { result.add(it) }
            i--
        }
        return result
    }

    private fun recordTransaction(tx: WalletTransaction) {
        val idx = (secureStore.getString(txIndexKey)?.toIntOrNull() ?: 0) + 1
        secureStore.putString(txIndexKey, idx.toString())
        secureStore.putString("$txPrefix$idx", serializeTx(tx))
    }

    private fun serializeTx(tx: WalletTransaction): String {
        val meta = tx.metadata.entries.joinToString("&") { "${escape(it.key)}=${escape(it.value)}" }
        return listOf(
            escape(tx.id),
            tx.type.name,
            tx.amountMinor.toString(),
            escape(tx.currency),
            tx.createdAtEpochMs.toString(),
            escape(tx.reference ?: ""),
            escape(meta)
        ).joinToString("|")
    }

    private fun parseTx(raw: String): WalletTransaction? {
        val parts = raw.split("|")
        if (parts.size < 7) return null
        val id = unescape(parts[0])
        val type = runCatching { WalletTransaction.Type.valueOf(parts[1]) }.getOrNull() ?: return null
        val amountMinor = parts[2].toLongOrNull() ?: return null
        val currency = unescape(parts[3])
        val createdAt = parts[4].toLongOrNull() ?: return null
        val reference = unescape(parts[5]).ifBlank { null }
        val metaRaw = unescape(parts[6])
        val metadata = if (metaRaw.isBlank()) emptyMap() else metaRaw.split("&").mapNotNull {
            val kv = it.split("=", limit = 2)
            if (kv.size != 2) null else unescape(kv[0]) to unescape(kv[1])
        }.toMap()
        return WalletTransaction(id, type, amountMinor, currency, createdAt, reference, metadata)
    }

    private fun escape(s: String): String = s.replace("%", "%25").replace("|", "%7C").replace("&", "%26").replace("=", "%3D")
    private fun unescape(s: String): String = s.replace("%7C", "|").replace("%26", "&").replace("%3D", "=").replace("%25", "%")
}

class BillingPaymentModule(
    app: Application,
    private val secureStore: SecureStore = AndroidKeystoreSecureStore(app),
    private val dispatcher: CoroutineDispatcher = Dispatchers.IO
) : PurchasesUpdatedListener, DefaultLifecycleObserver {

    private val appContext = app.applicationContext
    private val scope = CoroutineScope(SupervisorJob() + dispatcher)

    private val _events = MutableSharedFlow<PaymentEvent>(
        replay = 0,
        extraBufferCapacity = 64,
        onBufferOverflow = BufferOverflow.DROP_OLDEST
    )
    val events = _events.asSharedFlow()

    private val _billingReady = MutableStateFlow(false)
    val billingReady: StateFlow<Boolean> = _billingReady.asStateFlow()

    private val walletStore = WalletStore(secureStore)
    private val productDetailsCache = ConcurrentHashMap<String, ProductDetails>()

    private val billingClient: BillingClient = BillingClient.newBuilder(appContext)
        .setListener(this)
        .enablePendingPurchases()
        .build()

    init {
        ProcessLifecycleOwner.get().lifecycle.addObserver(this)
        connect()
    }

    override fun onStart(owner: LifecycleOwner) {
        connect()
    }

    override fun onStop(owner: LifecycleOwner) = Unit

    fun close() {
        ProcessLifecycleOwner.get().lifecycle.removeObserver(this)
        scope.cancel()
        if (billingClient.isReady) billingClient.endConnection()
    }

    @MainThread
    fun connect() {
        if (billingClient.isReady) {
            _billingReady.value = true
            scope.launch { _events.emit(PaymentEvent.BillingConnected(true)) }
            return
        }
        billingClient.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                val ok = billingResult.responseCode == BillingClient.BillingResponseCode.OK
                _billingReady.value = ok
                scope.launch {
                    _events.emit(PaymentEvent.BillingConnected(ok))
                    if (ok) queryActivePurchases()
                }
            }

            override fun onBillingServiceDisconnected() {
                _billingReady.value = false
                scope.launch { _events.emit(PaymentEvent.BillingConnected(false)) }
            }
        })
    }

    suspend fun queryProductDetails(
        inAppProductIds: List<String> = emptyList(),
        subProductIds: List<String> = emptyList()
    ): Map<String, ProductDetails> = withContext(dispatcher) {
        ensureReady()
        val result = LinkedHashMap<String, ProductDetails>()

        if (inAppProductIds.isNotEmpty()) {
            val inApp = queryDetails(inAppProductIds, BillingClient.ProductType.INAPP)
            result.putAll(inApp)
        }
        if (subProductIds.isNotEmpty()) {
            val subs = queryDetails(subProductIds, BillingClient.ProductType.SUBS)
            result.putAll(subs)
        }
        result
    }

    private suspend fun queryDetails(productIds: List<String>, type: String): Map<String, ProductDetails> {
        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(productIds.distinct().map {
                QueryProductDetailsParams.Product.newBuilder()
                    .setProductId(it)
                    .setProductType(type)
                    .build()
            })
            .build()

        val (billingResult, details) = suspendCancellableCoroutine<Pair<BillingResult, List<ProductDetails>>> { cont ->
            billingClient.queryProductDetailsAsync(params) { br, list ->
                if (cont.isActive) cont.resume(br to list)
            }
        }
        if (billingResult.responseCode != BillingClient.BillingResponseCode.OK) {
            scope.launch { _events.emit(PaymentEvent.Error("BILLING_QUERY_DETAILS", billingResult.debugMessage)) }
            return emptyMap()
        }
        details.forEach { productDetailsCache[it.productId] = it }
        return details.associateBy { it.productId }
    }

    @MainThread
    fun launchPurchaseFlow(
        activity: Activity,
        productId: String,
        offerToken: String? = null,
        obfuscatedAccountId: String? = null,
        obfuscatedProfileId: String? = null
    ): Boolean {
        if (!billingClient.isReady) {
            scope.launch { _events.emit(PaymentEvent.Error("BILLING_NOT_READY", "BillingClient not ready")) }
            connect()
            return false
        }

        val details = productDetailsCache[productId]
        if (details == null) {
            scope.launch { _events.emit(PaymentEvent.Error("MISSING_PRODUCT_DETAILS", "Call queryProductDetails() before launchPurchaseFlow")) }
            return false
        }

        val productParams = BillingFlowParams.ProductDetailsParams.newBuilder()
            .setProductDetails(details)
            .apply {
                val token = offerToken ?: details.subscriptionOfferDetails?.firstOrNull()?.offerToken
                if (!token.isNullOrBlank()) setOfferToken(token)
            }
            .build()

        val flowParams = BillingFlowParams.newBuilder()
            .setProductDetailsParamsList(listOf(productParams))
            .apply {
                if (!obfuscatedAccountId.isNullOrBlank()) setObfuscatedAccountId(obfuscatedAccountId)
                if (!obfuscatedProfileId.isNullOrBlank()) setObfuscatedProfileId(obfuscatedProfileId)
            }
            .build()

        val br = billingClient.launchBillingFlow(activity, flowParams)
        val ok = br.responseCode == BillingClient.BillingResponseCode.OK
        scope.launch {
            if (ok) _events.emit(PaymentEvent.PurchaseFlowLaunched(productId))
            else _events.emit(PaymentEvent.Error("BILLING_LAUNCH_FAILED", br.debugMessage))
        }
        return ok
    }

    override fun onPurchasesUpdated(billingResult: BillingResult, purchases: MutableList<Purchase>?) {
        if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && !purchases.isNullOrEmpty()) {
            scope.launch {
                _events.emit(PaymentEvent.PurchaseUpdated(purchases))
                purchases.forEach { handlePurchase(it) }
            }
        } else if (billingResult.responseCode == BillingClient.BillingResponseCode.USER_CANCELED) {
            scope.launch { _events.emit(PaymentEvent.Error("BILLING_CANCELED", "User canceled")) }
        } else if (billingResult.responseCode != BillingClient.BillingResponseCode.OK) {
            scope.launch { _events.emit(PaymentEvent.Error("BILLING_UPDATE_FAILED", billingResult.debugMessage)) }
        }
    }

    suspend fun queryActivePurchases() = withContext(dispatcher) {
        if (!billingClient.isReady) return@withContext
        val paramsInApp = QueryPurchasesParams.newBuilder().setProductType(BillingClient.ProductType.INAPP).build()
        val paramsSubs = QueryPurchasesParams.newBuilder().setProductType(BillingClient.ProductType.SUBS).build()

        val inApps = billingClient.queryPurchasesAsync(paramsInApp).purchasesList ?: emptyList()
        val subs = billingClient.queryPurchasesAsync(paramsSubs).purchasesList ?: emptyList()
        val all = (inApps + subs).distinctBy { it.purchaseToken }

        if (all.isNotEmpty()) {
            _events.emit(PaymentEvent.PurchaseUpdated(all))
            all.forEach { handlePurchase(it) }
        }
    }

    suspend fun acknowledgeIfNeeded(purchase: Purchase): Boolean = withContext(dispatcher) {
        ensureReady()
        if (purchase.purchaseState != Purchase.PurchaseState.PURCHASED) return@withContext false
        if (purchase.isAcknowledged) return@withContext true
        val params = AcknowledgePurchaseParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()
        val br = suspendCancellableCoroutine<BillingResult> { cont ->
            billingClient.acknowledgePurchase(params) { result ->
                if (cont.isActive) cont.resume(result)
            }
        }
        val ok = br.responseCode == BillingClient.BillingResponseCode.OK
        if (ok) _events.emit(PaymentEvent.PurchaseAcknowledged(purchase.purchaseToken))
        else _events.emit(PaymentEvent.Error("BILLING_ACK_FAILED", br.debugMessage))
        ok
    }

    suspend fun consumePurchase(purchaseToken: String): Boolean = withContext(dispatcher) {
        ensureReady()
        val params = ConsumeParams.newBuilder().setPurchaseToken(purchaseToken).build()
        val (br, token) = suspendCancellableCoroutine<Pair<BillingResult, String>> { cont ->
            billingClient.consumeAsync(params) { result, outToken ->
                if (cont.isActive) cont.resume(result to outToken)
            }
        }
        val ok = br.responseCode == BillingClient.BillingResponseCode.OK
        if (ok) _events.emit(PaymentEvent.PurchaseConsumed(token))
        else _events.emit(PaymentEvent.Error("BILLING_CONSUME_FAILED", br.debugMessage))
        ok
    }

    suspend fun handlePurchase(purchase: Purchase) = withContext(dispatcher) {
        when (purchase.purchaseState) {
            Purchase.PurchaseState.PENDING -> {
                _events.emit(PaymentEvent.Error("BILLING_PENDING", "Purchase is pending"))
            }
            Purchase.PurchaseState.PURCHASED -> {
                val acknowledged = acknowledgeIfNeeded(purchase)
                if (!acknowledged) return@withContext
                secureStore.putString("purchase_token_${purchase.purchaseToken}", purchase.purchaseTime.toString())
            }
            else -> Unit
        }
    }

    fun getWalletBalance(): Money = walletStore.getBalance()

    fun listRecentWalletTransactions(limit: Int = 50): List<WalletTransaction> = walletStore.listRecentTransactions(limit)

    fun setWalletCurrencyIfEmpty(currency: String) {
        walletStore.setCurrencyIfEmpty(currency)
    }

    suspend fun creditWallet(amountMinor: Long, currency: String, reference: String? = null, metadata: Map<String, String> = emptyMap()): WalletTransaction =
        withContext(dispatcher) {
            val tx = walletStore.applyTransaction(WalletTransaction.Type.CREDIT, amountMinor, currency, reference, metadata)
            _events.emit(PaymentEvent.WalletTransactionRecorded(tx))
            _events.emit(PaymentEvent.WalletBalanceChanged(walletStore.getBalance().amountMinor, walletStore.getBalance().currency))
            tx
        }

    suspend fun debitWallet(amountMinor: Long, currency: String, reference: String? = null, metadata: Map<String, String> = emptyMap()): WalletTransaction =
        withContext(dispatcher) {
            val tx = walletStore.applyTransaction(WalletTransaction.Type.DEBIT, amountMinor, currency, reference, metadata)
            _events.emit(PaymentEvent.WalletTransactionRecorded(tx))
            _events.emit(PaymentEvent.WalletBalanceChanged(walletStore.getBalance().amountMinor, walletStore.getBalance().currency))
            tx
        }

    private fun ensureReady() {
        if (!billingClient.isReady) throw IllegalStateException("BillingClient not ready")
    }
}